external_knowledge:
A game session is considered to have started in 2023 or later if its start time is on or after January 1, 2023; 
A game type's average score is calculated by taking the average of the average scores across all its game sessions; 
A game type's maximum tile value is the highest tile value achieved in any of its game sessions.

sql:
SELECT AVG(max_score) AS average_max_score
FROM game_sessions
WHERE ai_type = (SELECT strategy_name FROM ai_strategies WHERE strategy_id = 0);

SELECT epsilon_value
FROM epsilon_values
WHERE epsilon_id = 0;

SELECT epsilon_value
FROM epsilon_values
WHERE is_active = 1;

SELECT average_score
FROM rollout_simulations
WHERE session_id = 1;

SELECT MAX(best_tiles) AS max_best_tiles
FROM game_sessions
WHERE session_id = 1;

SELECT MAX(value) AS max_best_tile
FROM game_metrics
WHERE metric_name = 'best_tiles';
